import { describe, expect, it } from '@a0n/gnosis/test';
import { GnosisRegistry } from '../runtime/registry';
import {
  createWasmBridgeExecutionAst,
  executeWasmWithGnosis,
  registerWasmBridgeHandlers,
  type WasmExecutionManifest,
} from '../wasm-execution-bridge';

const WASM_DOUBLE_FIXTURE_BASE64 =
  '';

describe('wasm execution bridge', () => {
  it('registers the wasm bridge handlers', () => {
    const registry = new GnosisRegistry();
    const manifest: WasmExecutionManifest = {
      wasm_base64: WASM_DOUBLE_FIXTURE_BASE64,
      export_name: 'double_value',
      abi: 'scalar-v1',
      node_execution_plans: [],
    };

    registerWasmBridgeHandlers(registry, manifest);

    expect(registry.hasHandler('WasmBridgeEntry')).toBe(true);
    expect(registry.hasHandler('WasmBridgeCall')).toBe(true);
    expect(registry.hasHandler('WasmBridgeStatement')).toBe(true);
    expect(registry.hasHandler('WasmBridgeReturn')).toBe(true);
    expect(registry.hasHandler('WasmBridgeJoin')).toBe(true);
  });

  it('executes scalar-v1 guests through the gnosis runtime', async () => {
    const result = await executeWasmWithGnosis({
      ast: createWasmBridgeExecutionAst(),
      manifest: {
        wasm_base64: WASM_DOUBLE_FIXTURE_BASE64,
        export_name: 'double_value',
        abi: 'scalar-v1',
        node_execution_plans: [
          { node_id: 'wasm_entry', kind: 'entry' },
          { node_id: 'wasm_call', kind: 'call' },
          { node_id: 'wasm_return', kind: 'return' },
        ],
      },
      input: 7,
    });

    expect(result.payload).toBe(14);
  });

  it('executes json-v1 guests through the gnosis runtime', async () => {
    const result = await executeWasmWithGnosis({
      ast: createWasmBridgeExecutionAst(),
      manifest: {
        wasm_base64: WASM_DOUBLE_FIXTURE_BASE64,
        export_name: 'double_json',
        abi: 'json-v1',
        node_execution_plans: [
          { node_id: 'wasm_entry', kind: 'entry' },
          { node_id: 'wasm_call', kind: 'call' },
          { node_id: 'wasm_return', kind: 'return' },
        ],
      },
      input: {
        value: 21,
      },
    });

    expect(result.payload).toEqual({
      doubled: 42,
    });
  });
});
